134	// Dev-only signin bypass. Skips the edge functions + routes directly into the
135	// role's tab group. Kept inside `__DEV__` so Metro strips the component (and
136	// the fake tokens / UUIDs it closes over) from production bundles — top-level
137	// const declarations would survive dead-code removal (Codebase Patterns #96).
138	function DevRolePicker() {
139	  const { signIn } = useAuth();
140	
141	  const creatorUser = {
142	    id: '00000000-0000-0000-0000-000000000001',
143	    username: 'dev_creator',
144	    email: null,
145	    role: 'creator' as const,
146	    created_at: new Date(0).toISOString(),
147	    updated_at: new Date(0).toISOString(),
148	    deleted_at: null,
149	  };
150	  const listerUser = {
151	    id: '00000000-0000-0000-0000-000000000002',
152	    username: 'dev_lister',
153	    email: 'dev-lister@example.com',
154	    role: 'lister' as const,
155	    created_at: new Date(0).toISOString(),
156	    updated_at: new Date(0).toISOString(),
157	    deleted_at: null,
158	  };
159	
160	  return (
161	    <View style={styles.devBlock}>
162	      <Text style={[textStyles.caption, styles.devCaption]}>DEV BYPASS</Text>
163	      <ButtonPrimary
164	        label="Sign in as creator"
165	        onPress={() => signIn('dev-creator-token', creatorUser)}
166	        accessibilityLabel="Dev sign in as creator"
167	        testID="dev-signin-creator"
168	      />
169	      <View style={styles.spacer} />
170	      <ButtonSecondary
171	        label="Sign in as lister"
172	        onPress={() => signIn('dev-lister-token', listerUser)}
173	        accessibilityLabel="Dev sign in as lister"
174	        testID="dev-signin-lister"
175	      />
176	    </View>
177	  );
178	}
